import{_ as e,o as a,c as d,ag as o}from"./chunks/framework.CvgP6Fyv.js";const m=JSON.parse('{"title":"Generated Project Commands","description":"","frontmatter":{},"headers":[],"relativePath":"reference/generated-commands.md","filePath":"reference/generated-commands.md","lastUpdated":null}'),n={name:"reference/generated-commands.md"};function r(i,t,s,l,c,h){return a(),d("div",null,[...t[0]||(t[0]=[o(`<h1 id="generated-project-commands" tabindex="-1">Generated Project Commands <a class="header-anchor" href="#generated-project-commands" aria-label="Permalink to &quot;Generated Project Commands&quot;">​</a></h1><p>All commands available in a generated experiment project. Run them from the project root after <code>pnpm install</code>.</p><h2 id="development" tabindex="-1">Development <a class="header-anchor" href="#development" aria-label="Permalink to &quot;Development&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>pnpm start 0</code></td><td>Watch variation 1 (<code>src/js/v1/</code>). Rebuilds on save and copies IIFE bundle to clipboard.</td></tr><tr><td><code>pnpm start 1</code></td><td>Watch variation 2 (<code>src/js/v2/</code>). Clipboard copy enabled.</td></tr><tr><td><code>pnpm start N</code></td><td>Watch variation N+1. The argument is zero-indexed.</td></tr><tr><td><code>pnpm dev</code></td><td>Watch all variations simultaneously. No clipboard copy.</td></tr></tbody></table><h2 id="build" tabindex="-1">Build <a class="header-anchor" href="#build" aria-label="Permalink to &quot;Build&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>pnpm build</code></td><td>Production build. Runs Biome lint first. Builds all variations to <code>dist/</code>. Aborts on lint errors.</td></tr></tbody></table><p>Build output:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dist/</span></span>
<span class="line"><span>├── v1/v1.js   ← IIFE bundle for variation 1</span></span>
<span class="line"><span>├── v2/v2.js   ← IIFE bundle for variation 2</span></span>
<span class="line"><span>└── vN/vN.js</span></span></code></pre></div><h2 id="linting" tabindex="-1">Linting <a class="header-anchor" href="#linting" aria-label="Permalink to &quot;Linting&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th></tr></thead><tbody><tr><td><code>pnpm lint</code></td><td>Runs <code>biome check src/</code>. Reports violations. Exits non-zero if any errors are found.</td></tr><tr><td><code>pnpm format</code></td><td>Runs <code>biome check --write src/</code>. Auto-fixes formatting violations in place.</td></tr></tbody></table><h2 id="testing" tabindex="-1">Testing <a class="header-anchor" href="#testing" aria-label="Permalink to &quot;Testing&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Command</th><th>What it does</th><th>Available</th></tr></thead><tbody><tr><td><code>pnpm test:e2e</code></td><td>Runs Playwright tests in <code>e2e/</code>.</td><td>Only when E2E was enabled at scaffold time</td></tr></tbody></table><h2 id="notes" tabindex="-1">Notes <a class="header-anchor" href="#notes" aria-label="Permalink to &quot;Notes&quot;">​</a></h2><ul><li><code>pnpm build</code> is the only command that enforces a clean lint gate (build aborts on lint errors).</li><li><code>pnpm lint</code> in watch mode reports errors but does not abort the watcher.</li><li>All commands require Node 20+ and pnpm 10.30.1. Run <code>nvm use 24</code> first if you&#39;re on an older Node.</li></ul>`,14)])])}const b=e(n,[["render",r]]);export{m as __pageData,b as default};
